#!/usr/bin/env python3
"""Transformer tail-hidden sieve gate: does the qwen2.5-0.5b final pre-lm_head hidden
(get_x_residual of the LAST prompt token) separate PARAPHRASES (within-group) from
UNRELATED prompts (across-group)? RAW vs MEAN-CENTERED (remove the common-mode "rogue
dimension" that makes transformers anisotropic).

Mirrors resonance-anisotropy-diag.py / scaling-trend-analysis.py but on the FULL set
(all g* paraphrase groups + u_* unrelated singletons) for one activation dump.

Usage: transformer-resonance-analysis.py transformer_acts_qwen05b.json
"""
import json, sys, itertools
import numpy as np

P = sys.argv[1] if len(sys.argv) > 1 else \
    "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad/transformer_acts_qwen05b.json"
d = json.load(open(P))
recs = d["records"]
D = d["hidden_dim"]
groups = [r["group"] for r in recs]
X = np.array([r["activation"] for r in recs], dtype=np.float64)  # (N, D)
N = len(recs)

def is_para(g): return g.startswith("g")

def cos(a, b):
    na, nb = np.linalg.norm(a), np.linalg.norm(b)
    return 0.0 if na == 0 or nb == 0 else float(a @ b / (na * nb))

# within = both same paraphrase group; across = every other pair (incl. all u_* pairs
# and cross-group pairs). This is the sieve's real job: collide paraphrases, separate
# everything else.
within, across = [], []
for i, j in itertools.combinations(range(N), 2):
    if groups[i] == groups[j] and is_para(groups[i]):
        within.append((i, j))
    else:
        across.append((i, j))

def report(tag, M):
    w = np.array([cos(M[i], M[j]) for i, j in within])
    a = np.array([cos(M[i], M[j]) for i, j in across])
    sep = w.mean() - a.mean()
    # ordering accuracy: P(within pair more similar than a random across pair)
    order_acc = 100 * np.mean([ww > aa for ww in w for aa in a])
    # best single-threshold split accuracy over all pairs
    allv = np.concatenate([w, a]); lab = np.concatenate([np.ones_like(w), np.zeros_like(a)])
    best = max(((allv >= t) == lab).mean() for t in np.unique(allv))
    clean = w.min() - a.max()
    print(f"  {tag:8s} D={D}: sep={sep:+.3f} order-acc={order_acc:5.1f}% "
          f"best-split={100*best:4.1f}% clean-margin={clean:+.3f} "
          f"[w={w.mean():.3f}±{w.std():.3f} a={a.mean():.3f}±{a.std():.3f} "
          f"wmin={w.min():.3f} amax={a.max():.3f}]")
    return sep, order_acc

print(f"N={N} prompts, D={D}, within-pairs={len(within)}, across-pairs={len(across)}")
para_groups = sorted(set(g for g in groups if is_para(g)))
print(f"paraphrase groups: {para_groups}")
print()
report("RAW", X)
mu = X.mean(0)
report("CENTERED", X - mu)

# common-mode diagnostic: how much of the raw cosine is the shared mean direction?
munorm = np.linalg.norm(mu)
avgnorm = np.mean(np.linalg.norm(X, axis=1))
print(f"\n  anisotropy: ||mean||={munorm:.2f}  avg||x||={avgnorm:.2f}  "
      f"mean/avg-norm ratio={munorm/avgnorm:.3f} (higher => more common-mode / anisotropic)")
